227	// drainServiceEvents reads service events and returns the final-event payload,
228	// the accumulated tool-call log, the routing decision (when present in the
229	// routing_decision start event), and the power of the selected model (0 when
230	// the routing_decision event does not include candidate power components).
231	// A sustained run of no-op compaction telemetry is converted into a synthetic
232	// stalled final so execute-bead result details identify the time-based
233	// breaker instead of waiting for the outer wall clock.
234	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, []ToolCallEntry, *serviceRoutingActual, int) {
235		var final *serviceFinalData
236		var routing *serviceRoutingActual
237		var routingPower int
238		var toolCalls []ToolCallEntry
239		pending := make(map[string]*ToolCallEntry) // call_id -> entry awaiting result
240		var noopCompactions serviceNoopCompactionStreak
241		var noopTimer *time.Timer
242		var noopTimerC <-chan time.Time
243		defer func() { stopNoopCompactionTimer(noopTimer) }()
244	
245		for {
246			select {
247			case <-noopTimerC:
248				detail := noopCompactions.detail(serviceNoopCompactionWallClockLimit, serviceNoopCompactionWallClockLimit)
249				return &serviceFinalData{
250					Status: "stalled",
251					Error:  detail,
252				}, toolCallsWithPending(toolCalls, pending), routing, routingPower
253			case ev, ok := <-events:
254				if !ok {
255					// Any tool_call without a matching tool_result still gets recorded.
256					return final, toolCallsWithPending(toolCalls, pending), routing, routingPower
257				}
258				if isNoopCompactionEvent(ev) {
259					detail, started := noopCompactions.record(eventTimestamp(ev), serviceNoopCompactionWallClockLimit)
260					if started {
261						noopTimer, noopTimerC = resetNoopCompactionTimer(noopTimer, serviceNoopCompactionWallClockLimit)
262					}
263					if detail != "" {
264						return &serviceFinalData{
265							Status: "stalled",
266							Error:  detail,
267						}, toolCallsWithPending(toolCalls, pending), routing, routingPower
268					}
269					continue
270				}
271				if isServiceProgressEvent(ev) {
272					noopCompactions.reset()
273					stopNoopCompactionTimer(noopTimer)
274					noopTimerC = nil
275				}
276	
277				switch string(ev.Type) {
278				case serviceEventRoutingDecision:
279					var payload struct {
280						Harness    string `json:"harness"`
281						Provider   string `json:"provider"`
282						Model      string `json:"model"`
283						Candidates []struct {
284							Model      string `json:"model"`
285							Eligible   bool   `json:"eligible"`
286							Components struct {
287								Power int `json:"power"`
288							} `json:"components"`
289						} `json:"candidates"`
290					}
291					if err := json.Unmarshal(ev.Data, &payload); err == nil {
292						routing = &serviceRoutingActual{
293							Harness:  payload.Harness,
294							Provider: payload.Provider,
295							Model:    payload.Model,
296						}
297						for _, c := range payload.Candidates {
298							if c.Eligible && c.Model == payload.Model {
299								routingPower = c.Components.Power
300								break
301							}
302						}
303					}
304				case serviceEventToolCall:
305					var data serviceToolCallData
306					if err := json.Unmarshal(ev.Data, &data); err == nil {
307						entry := &ToolCallEntry{
308							Tool:  data.Name,
309							Input: string(data.Input),
310						}
311						pending[data.ID] = entry
312					}
313				case serviceEventToolResult:
314					var data serviceToolResultData
315					if err := json.Unmarshal(ev.Data, &data); err == nil {
316						if entry, ok := pending[data.ID]; ok {
317							entry.Output = data.Output
318							entry.Error = data.Error
319							entry.Duration = int(data.DurationMS)
320							toolCalls = append(toolCalls, *entry)
321							delete(pending, data.ID)
322						}
323					}
324				case serviceEventFinal:
325					var data serviceFinalData
326					if err := json.Unmarshal(ev.Data, &data); err == nil {
327						final = &data
328					}
329				}
330			}
331		}
332	}
