334	func resetNoopCompactionTimer(timer *time.Timer, limit time.Duration) (*time.Timer, <-chan time.Time) {
335		if limit <= 0 {
336			return timer, nil
337		}
338		if timer == nil {
339			timer = time.NewTimer(limit)
340			return timer, timer.C
341		}
342		stopNoopCompactionTimer(timer)
343		timer.Reset(limit)
344		return timer, timer.C
345	}
346	
347	func stopNoopCompactionTimer(timer *time.Timer) {
348		if timer == nil {
349			return
350		}
351		if !timer.Stop() {
352			select {
353			case <-timer.C:
354			default:
355			}
356		}
357	}
358	
359	type serviceNoopCompactionStreak struct {
360		start time.Time
361		count int
362	}
363	
364	func (s *serviceNoopCompactionStreak) record(ts time.Time, limit time.Duration) (string, bool) {
365		if limit <= 0 {
366			return "", false
367		}
368		if ts.IsZero() {
369			ts = time.Now().UTC()
370		}
371		started := false
372		if s.count == 0 {
373			s.start = ts
374			started = true
375		}
376		s.count++
377		elapsed := ts.Sub(s.start)
378		if elapsed < limit {
379			return "", started
380		}
381		return s.detail(elapsed, limit), started
382	}
383	
384	func (s *serviceNoopCompactionStreak) detail(elapsed, limit time.Duration) string {
385		if elapsed < limit {
386			elapsed = limit
387		}
388		return fmt.Sprintf("%s: time-based breaker fired after %s of consecutive no-op compaction events (limit %s, count %d)",
389			serviceNoopCompactionWallClockReason,
390			elapsed.Round(time.Second),
391			limit.Round(time.Second),
392			s.count)
393	}
394	
395	func (s *serviceNoopCompactionStreak) reset() {
396		s.start = time.Time{}
397		s.count = 0
398	}
399	
400	func eventTimestamp(ev agentlib.ServiceEvent) time.Time {
401		if !ev.Time.IsZero() {
402			return ev.Time
403		}
404		return time.Now().UTC()
405	}
406	
407	func isNoopCompactionEvent(ev agentlib.ServiceEvent) bool {
408		switch string(ev.Type) {
409		case serviceEventCompaction, serviceEventCompactionEnd:
410		default:
411			return false
412		}
413		var payload struct {
414			NoCompaction bool `json:"no_compaction"`
415		}
416		if err := json.Unmarshal(ev.Data, &payload); err != nil {
417			return false
418		}
419		return payload.NoCompaction
420	}
421	
422	func isServiceProgressEvent(ev agentlib.ServiceEvent) bool {
423		switch string(ev.Type) {
424		case serviceEventTextDelta, serviceEventToolCall, serviceEventToolResult, serviceEventCompaction, serviceEventCompactionEnd:
425			return true
426		default:
427			return false
428		}
429	}
430	
431	func toolCallsWithPending(toolCalls []ToolCallEntry, pending map[string]*ToolCallEntry) []ToolCallEntry {
432		for _, entry := range pending {
433			toolCalls = append(toolCalls, *entry)
434		}
435		return toolCalls
436	}
