102	// executeOnService dispatches against a pre-built svc using the durable
103	// knobs from rcfg and per-invocation plumbing from runtime, then records
104	// one session-index row. It is the inlined replacement for the retired
105	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
106	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
107		if svc == nil {
108			return nil, fmt.Errorf("agent: nil service")
109		}
110		if ctx == nil {
111			ctx = context.Background()
112		}
113	
114		promptText := runtime.Prompt
115		if runtime.PromptFile != "" {
116			data, err := readPromptFileBounded(runtime.PromptFile)
117			if err != nil {
118				return nil, fmt.Errorf("agent: read prompt file: %w", err)
119			}
120			promptText = string(data)
121		}
122		if promptText == "" {
123			return nil, fmt.Errorf("agent: prompt is required")
124		}
125	
126		wd := runtime.WorkDir
127		if wd == "" {
128			wd = workDir
129		}
130		if wd == "" {
131			wd, _ = os.Getwd()
132		}
133	
134		idle := rcfg.Timeout()
135		if idle <= 0 {
136			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
137		}
138		wall := rcfg.WallClock()
139		if wall <= 0 {
140			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
141		}
142	
143		sessionLogDir := runtime.SessionLogDirOverride
144		if sessionLogDir == "" {
145			sessionLogDir = rcfg.SessionLogDir()
146		}
147		if sessionLogDir == "" {
148			sessionLogDir = ResolveLogDir(workDir, "")
149		}
150	
151		pt := rcfg.Passthrough()
152	
153		harness := runtime.HarnessOverride
154		if harness == "" {
155			harness = pt.Harness
156		}
157	
158		model := runtime.ModelOverride
159		if model == "" {
160			model = pt.Model
161		}
162	
163		permissions := runtime.PermissionsOverride
164		if permissions == "" {
165			permissions = rcfg.Permissions()
166		}
167	
168		providerTimeout := ResolveProviderRequestTimeout(workDir, pt.Provider, model, rcfg.ProviderRequestTimeout())
169	
170		minPower := rcfg.MinPower()
171		if runtime.MinPowerOverride > 0 {
172			minPower = runtime.MinPowerOverride
173		}
174	
175		req := agentlib.ServiceExecuteRequest{
176			Prompt:          promptText,
177			Model:           model,
178			Profile:         rcfg.Profile(),
179			Provider:        pt.Provider,
180			Harness:         harness,
181			ModelRef:        rcfg.ModelRef(),
182			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
183			Permissions:     permissions,
184			WorkDir:         wd,
185			Timeout:         wall,
186			IdleTimeout:     idle,
187			ProviderTimeout: providerTimeout,
188			SessionLogDir:   sessionLogDir,
189			Metadata:        runtime.Correlation,
190			MinPower:        minPower,
191			MaxPower:        rcfg.MaxPower(),
192		}
193	
194		cancelCtx, cancel := context.WithCancel(ctx)
195		defer cancel()
196	
197		start := time.Now().UTC()
198		events, err := svc.Execute(cancelCtx, req)
199		if err != nil {
200			return nil, fmt.Errorf("agent: execute: %w", err)
201		}
202	
203		final, toolCalls, routing, actualPower := drainServiceEvents(events)
204		finishedAt := time.Now().UTC()
205		elapsed := finishedAt.Sub(start)
206	
207		result := &Result{
208			Harness:    harness,
209			Model:      model,
210			DurationMS: int(elapsed.Milliseconds()),
211			ToolCalls:  toolCalls,
212		}
213		if routing != nil {
214			result.Provider = routing.Provider
215			if routing.Model != "" {
216				result.Model = routing.Model
217			}
218			if routing.Harness != "" {
219				result.Harness = routing.Harness
220			}
221		}
222		if actualPower > 0 {
223			result.ActualPower = actualPower
224		}
225		if final != nil {
226			// Normalized final text from the upstream harness (agent-32e8ff5e);
227			// reviewer verdict extraction now parses this instead of raw stream
228			// frames (ddx-7bc0c8d5).
229			result.Output = final.FinalText
230			if final.Usage != nil {
231				// v0.9.1: Usage fields became *int (nullable).
232				if final.Usage.InputTokens != nil {
233					result.InputTokens = *final.Usage.InputTokens
234				}
235				if final.Usage.OutputTokens != nil {
236					result.OutputTokens = *final.Usage.OutputTokens
237				}
238				if final.Usage.TotalTokens != nil {
239					result.Tokens = *final.Usage.TotalTokens
240				}
241			}
242			if final.CostUSD > 0 {
243				result.CostUSD = final.CostUSD
244			}
245			if final.RoutingActual != nil {
246				if result.Provider == "" {
247					result.Provider = final.RoutingActual.Provider
248				}
249				if final.RoutingActual.Model != "" {
250					result.Model = final.RoutingActual.Model
251				}
252			}
253			switch final.Status {
254			case "success", "":
255				// happy path
256			case "stalled":
257				result.ExitCode = 1
258				if final.Error != "" {
259					result.Error = "stalled: " + final.Error
260				} else {
261					result.Error = "stalled"
262				}
263			case "timed_out":
264				result.ExitCode = 1
265				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
266			case "cancelled":
267				result.ExitCode = 1
268				result.Error = "cancelled"
269			default:
270				result.ExitCode = 1
271				if final.Error != "" {
272					result.Error = final.Error
273				} else {
274					result.Error = final.Status
275				}
276			}
277			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
278			if final.SessionLogPath != "" {
279				result.AgentSessionID = final.SessionLogPath
280			}
281		}
282		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
283			Harness:     harness,
284			Model:       model,
285			Provider:    pt.Provider,
286			Effort:      rcfg.Effort(),
287			Correlation: runtime.Correlation,
288		}, result, start, finishedAt)
289		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
290		return result, nil
291	}
