387	// ValidateForExecuteLoopViaService is the production replacement for
388	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
389	// will pick at claim time). When harness is specified it confirms the harness
390	// exists in the service registry and (when model is set) attempts a
391	// ResolveRoute pre-flight.
392	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
393		if harnessName == "" {
394			return nil
395		}
396		if ctx == nil {
397			ctx = context.Background()
398		}
399		svc, err := NewServiceFromWorkDir(workDir)
400		if err != nil {
401			return fmt.Errorf("agent: build service: %w", err)
402		}
403		infos, err := svc.ListHarnesses(ctx)
404		if err != nil {
405			return fmt.Errorf("agent: list harnesses: %w", err)
406		}
407		found := false
408		for _, info := range infos {
409			if info.Name == harnessName {
410				found = true
411				if !info.Available {
412					return fmt.Errorf("agent: harness %s not available", harnessName)
413				}
414				break
415			}
416		}
417		if !found {
418			return fmt.Errorf("agent: unknown harness: %s", harnessName)
419		}
420	
421		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
422		// model is provided and provider/model-ref are not set.
423		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
424			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
425				Model:    model,
426				Harness:  harnessName,
427				ModelRef: modelRef,
428				Provider: provider,
429			}); err != nil {
430				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
431			}
432		}
433		return nil
434	}
