492	// GetRunGraphQL implements RunsStateProvider.
493	func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
494		if id == "" {
495			return nil, false
496		}
497		// Search all projects.
498		for _, proj := range s.GetProjects(false) {
499			runs := s.loadRunsForProject(proj.ID, proj.Path)
500			for _, r := range runs {
501				if r.ID == id {
502					return r, true
503				}
504			}
505		}
506		return nil, false
507	}
