357	func readSessionIndexFiles(files []string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
358		var out []SessionIndexEntry
359		for _, file := range files {
360			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
361				if !sessionIndexEntryInRange(entry, q) {
362					return nil
363				}
364				out = append(out, entry)
365				return nil
366			})
367			if err != nil {
368				return nil, err
369			}
370		}
371		return out, nil
372	}
