374	func FindSessionIndex(logDir, id string) (SessionIndexEntry, bool, error) {
375		files, err := SessionIndexShardFiles(logDir, SessionIndexQuery{})
376		if err != nil {
377			return SessionIndexEntry{}, false, err
378		}
379		for _, file := range files {
380			var found SessionIndexEntry
381			ok := false
382			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
383				if entry.ID == id {
384					found = entry
385					ok = true
386					return fmt.Errorf("found")
387				}
388				return nil
389			})
390			if ok {
391				return found, true, nil
392			}
393			if err != nil && err.Error() != "found" {
394				return SessionIndexEntry{}, false, err
395			}
396		}
397		return SessionIndexEntry{}, false, nil
398	}
