400	func SessionIndexShardFiles(logDir string, q SessionIndexQuery) ([]string, error) {
401		dir := SessionIndexDir(logDir)
402		entries, err := os.ReadDir(dir)
403		if os.IsNotExist(err) {
404			return nil, nil
405		}
406		if err != nil {
407			return nil, err
408		}
409		var files []string
410		for _, ent := range entries {
411			if ent.IsDir() {
412				continue
413			}
414			name := ent.Name()
415			if !strings.HasPrefix(name, "sessions-") || !strings.HasSuffix(name, ".jsonl") {
416				continue
417			}
418			if !sessionShardIntersects(name, q) {
419				continue
420			}
421			files = append(files, filepath.Join(dir, name))
422		}
423		sort.Sort(sort.Reverse(sort.StringSlice(files)))
424		return files, nil
425	}
