427	func ReindexLegacySessions(projectRoot, logDir string) (int, error) {
428		legacyPath := filepath.Join(logDir, LegacySessionsFileName)
429		readPath := legacyPath
430		if _, err := os.Stat(readPath); os.IsNotExist(err) {
431			readPath = filepath.Join(logDir, LegacySessionsRenameName)
432			if _, legacyErr := os.Stat(readPath); os.IsNotExist(legacyErr) {
433				return 0, nil
434			} else if legacyErr != nil {
435				return 0, legacyErr
436			}
437		} else if err != nil {
438			return 0, err
439		}
440	
441		existing, err := existingSessionIndexIDs(logDir)
442		if err != nil {
443			return 0, err
444		}
445		count := 0
446		err = ForEachJSONL[SessionEntry](readPath, func(entry SessionEntry) error {
447			if entry.ID == "" {
448				return nil
449			}
450			if _, ok := existing[entry.ID]; ok {
451				return nil
452			}
453			idx := SessionIndexEntryFromLegacy(projectRoot, entry)
454			if err := AppendSessionIndex(logDir, idx, entry.Timestamp.UTC()); err != nil {
455				return err
456			}
457			existing[entry.ID] = struct{}{}
458			count++
459			return nil
460		})
461		if err != nil {
462			return count, err
463		}
464		if readPath == legacyPath {
465			renamed := filepath.Join(logDir, LegacySessionsRenameName)
466			if _, err := os.Stat(renamed); os.IsNotExist(err) {
467				if err := os.Rename(legacyPath, renamed); err != nil {
468					return count, err
469				}
470			}
471		}
472		return count, nil
473	}
