546	func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
547		if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
548			return false
549		}
550		if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
551			return false
552		}
553		return true
554	}
