556	func sessionShardIntersects(name string, q SessionIndexQuery) bool {
557		month, ok := sessionShardMonth(name)
558		if !ok {
559			return false
560		}
561		next := month.AddDate(0, 1, 0)
562		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
563			now := time.Now().UTC()
564			current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
565			previous := current.AddDate(0, -1, 0)
566			return month.Equal(current) || month.Equal(previous)
567		}
568		if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
569			return false
570		}
571		if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
572			return false
573		}
574		return true
575	}
576	
577	func sessionShardMonth(name string) (time.Time, bool) {
578		if len(name) != len("sessions-2006-01.jsonl") {
579			return time.Time{}, false
580		}
581		month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
582		if err != nil {
583			return time.Time{}, false
584		}
585		return month.UTC(), true
586	}
