617	func relativizePath(root, path string) string {
618		if path == "" {
619			return ""
620		}
621		if root != "" && filepath.IsAbs(path) {
622			if rel, err := filepath.Rel(root, path); err == nil && !strings.HasPrefix(rel, "..") {
623				return filepath.ToSlash(rel)
